{
    "title": "Zaimki wzajemne a zaimki zwrotne",
    "intro": "Porównanie użycia <strong>each other / one another</strong> i zaimków zwrotnych:",
    "rows": [
        {
            "en": "They love <strong>each other</strong>.",
            "ua": "Oni się kochają.",
            "note": "Działanie jest wzajemne: on kocha ją, a ona kocha jego."
        },
        {
            "en": "She loves <strong>herself</strong>.",
            "ua": "Ona kocha samą siebie.",
            "note": "Działanie wraca do tej samej osoby."
        },
        {
            "en": "We see <strong>each other</strong> often.",
            "ua": "Często się widujemy.",
            "note": "Chodzi o kontakt między dwiema lub kilkoma osobami."
        },
        {
            "en": "I see <strong>myself</strong> in the mirror.",
            "ua": "Widzę siebie w lustrze.",
            "note": "To przykład zaimka zwrotnego, nie wzajemnego."
        },
        {
            "en": "They hugged <strong>each other</strong>.",
            "ua": "Objęli się nawzajem.",
            "note": "Obie strony wykonują tę samą czynność wobec siebie."
        },
        {
            "en": "He hurt <strong>himself</strong>.",
            "ua": "Zranił się.",
            "note": "Czynność dotyczy tej samej osoby."
        }
    ]
}
